import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"Administration","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/admin.md","filePath":"en/guide/admin.md"}'),o={name:"en/guide/admin.md"};function r(n,e,l,d,u,c){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="administration" tabindex="-1">Administration <a class="header-anchor" href="#administration" aria-label="Permalink to &quot;Administration&quot;">​</a></h1><p>The <strong>Administration</strong> page is restricted to users with the <strong>admin</strong> role. It allows you to manage users, monitor jobs, and view system statistics.</p><hr><h2 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h2><h3 id="user-list" tabindex="-1">User List <a class="header-anchor" href="#user-list" aria-label="Permalink to &quot;User List&quot;">​</a></h3><p>The table displays all users on the instance with:</p><ul><li>Email, display name, avatar</li><li>Role (user / admin)</li><li>Number of connected Gmail accounts</li><li>Storage space used</li><li>Last sign-in date</li><li>Status (active / inactive)</li></ul><p>The list is paginated and supports searching by email or name.</p><blockquote><p>📸 <em>Suggested screenshot: user table with the columns mentioned above</em></p></blockquote><h3 id="edit-a-user" tabindex="-1">Edit a User <a class="header-anchor" href="#edit-a-user" aria-label="Permalink to &quot;Edit a User&quot;">​</a></h3><p>Click on a user to modify:</p><ul><li><strong>Role</strong>: promote to admin or demote to user</li><li><strong>Quotas</strong>: <ul><li>Maximum number of Gmail accounts (default: 5)</li><li>Archive storage quota (default: 1 GB)</li></ul></li><li><strong>Status</strong>: enable or disable the account</li></ul><blockquote><p>📸 <em>Suggested screenshot: user edit form with role, quotas, and status fields</em></p></blockquote><hr><h2 id="global-jobs" tabindex="-1">Global Jobs <a class="header-anchor" href="#global-jobs" aria-label="Permalink to &quot;Global Jobs&quot;">​</a></h2><p>The <strong>Jobs</strong> tab displays jobs from <strong>all users</strong> with:</p><ul><li>The user who launched the job</li><li>The type and status</li><li>The progress</li><li>The creation date</li></ul><p>Administrators can cancel any running job.</p><hr><h2 id="system-statistics" tabindex="-1">System Statistics <a class="header-anchor" href="#system-statistics" aria-label="Permalink to &quot;System Statistics&quot;">​</a></h2><p>The <strong>Statistics</strong> tab displays:</p><ul><li>Total number of users</li><li>Number of connected Gmail accounts</li><li>Total storage space used</li><li>Number of running jobs</li></ul><blockquote><p>📸 <em>Suggested screenshot: admin dashboard with system statistics</em></p></blockquote><hr><h2 id="integrity-check" tabindex="-1">Integrity Check <a class="header-anchor" href="#integrity-check" aria-label="Permalink to &quot;Integrity Check&quot;">​</a></h2><p>Administrators can verify the consistency between EML files on the NAS and the PostgreSQL index:</p><ul><li><strong>Missing files</strong>: referenced in the database but absent from disk</li><li><strong>Orphan files</strong>: present on disk without a database record</li><li><strong>Corrupted files</strong>: empty files (0 bytes)</li></ul><p>The check can be launched manually or runs automatically <strong>every night at 3 AM</strong>. If an issue is found, an <code>integrity.failed</code> webhook event is triggered.</p><blockquote><p>📸 <em>Suggested screenshot: integrity check result (healthy status / issues detected)</em></p></blockquote>',29)])])}const g=t(o,[["render",r]]);export{m as __pageData,g as default};
